import type { NordicRenderingContextAssets } from '../../common/types';

import { getAssetsCDN, getAssetsPrefix } from '@nordic/assets-config';
import { assetsCache } from '@nordic/fs-cache';

export function getAssetsData(
  mainEntry?: string,
): NordicRenderingContextAssets {
  return {
    cdn: getAssetsCDN(),
    prefix: getAssetsPrefix(),
    manifest: assetsCache.manifest,
    mainAssetsNames: mainEntry
      ? {
          scripts: assetsCache.getMainScriptsNames(mainEntry),
          styles: assetsCache.getMainStylesNames(mainEntry),
        }
      : { scripts: new Set(), styles: new Set() },
  };
}
